import {
  BrowserRouter,
  Routes,
  Route
} from "react-router-dom";

import Navbar from "./components/Navbar";

function Home() {
  return (
    <div className="container mt-5">
      <h1>Book A Doctor</h1>
      <p>
        Healthcare Appointment Booking System
      </p>
    </div>
  );
}

function Login() {
  return (
    <div className="container mt-5">
      <h2>Login Page</h2>
    </div>
  );
}

function Register() {
  return (
    <div className="container mt-5">
      <h2>Register Page</h2>
    </div>
  );
}

function Doctors() {
  return (
    <div className="container mt-5">
      <h2>Doctors Page</h2>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>

      <Navbar />

      <Routes>

        <Route
          path="/"
          element={<Home />}
        />

        <Route
          path="/login"
          element={<Login />}
        />

        <Route
          path="/register"
          element={<Register />}
        />

        <Route
          path="/doctors"
          element={<Doctors />}
        />

      </Routes>

    </BrowserRouter>
  );
}

export default App;
